package ir.tahamohamadi.blog.post; import ir.tahamohamadi.common.domain.LanguageCode; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*;
public interface BlogPostTranslationRepository extends JpaRepository<BlogPostTranslation,UUID>{ @Query("select t from BlogPostTranslation t join t.blogPost p where t.languageCode=:language and lower(t.slug)=lower(:slug) and t.deletedAt is null and p.deletedAt is null and p.status='PUBLISHED'") Optional<BlogPostTranslation> findPublishedByLanguageAndSlug(@Param("language") LanguageCode language,@Param("slug") String slug); @Query("select t from BlogPostTranslation t join t.blogPost p where t.languageCode=:language and t.deletedAt is null and p.deletedAt is null and p.status='PUBLISHED' order by p.publishedAt desc,p.id desc") List<BlogPostTranslation> findPublishedByLanguage(@Param("language") LanguageCode language,Pageable pageable); List<BlogPostTranslation> findByBlogPostIdAndDeletedAtIsNull(UUID postId); @Query(value="select t.* from blog_post_translation t join blog_post p on p.id=t.blog_post_id where t.language_code=:language and t.deleted_at is null and p.deleted_at is null and p.status='PUBLISHED' and t.search_vector @@ plainto_tsquery(case when :language='en' then 'english'::regconfig else 'simple'::regconfig end,:query) order by p.published_at desc,p.id desc",nativeQuery=true) List<BlogPostTranslation> searchPublishedByLanguage(@Param("language") String language,@Param("query") String query); }
